class Solution:
    def cloneGraph(self, node: 'Node') -> 'Node':
        if not node: return None
        oldToNew = {}
        def dfs(n):
            if n in oldToNew: return oldToNew[n]
            copy = Node(n.val)
            oldToNew[n] = copy
            for nei in n.neighbors:
                copy.neighbors.append(dfs(nei))
            return copy
        return dfs(node)

